import React, { useState } from 'react';
import { FiPackage, FiTruck, FiBox, FiGlobe, FiBriefcase, FiSearch, FiCpu, FiX } from 'react-icons/fi';

const Home = () => {
  const [showForm, setShowForm] = useState(false);
  const [selectedService, setSelectedService] = useState('');
  const [formData, setFormData] = useState({ name: '', phone: '', from: '', to: '', weight: '' });

  // WhatsApp var message pathvnyache function
  const handleWhatsApp = (e) => {
    e.preventDefault();
    const message = `*Navin Booking - Apni Manzil*%0A--------------------------%0A*Service:* ${selectedService}%0A*Customer:* ${formData.name}%0A*Phone:* ${formData.phone}%0A*From:* ${formData.from}%0A*To:* ${formData.to}%0A*Weight:* ${formData.weight}`;
    
    // Tumcha WhatsApp number ithe taka (Ex: 9198XXXXXXXX)
    window.open(`https://wa.me/91XXXXXXXXXX?text=${message}`, '_blank');
    setShowForm(false);
  };

  const ServiceCard = ({ icon, title, desc, btnColor }) => (
    <div className="col">
      <div className="premium-card h-100 border-0 shadow-lg text-center p-4 rounded-4" 
           style={{ background: 'rgba(255, 255, 255, 0.9)', backdropFilter: 'blur(10px)', transition: '0.3s' }}>
        <div className="mb-3 d-flex justify-content-center" style={{ fontSize: '3rem', color: btnColor }}>{icon}</div>
        <h6 className="fw-bold mb-2">{title}</h6>
        <p className="text-muted small mb-4">{desc}</p>
        <button 
          onClick={() => { setSelectedService(title); setShowForm(true); }}
          className="btn btn-sm w-100 rounded-pill text-white fw-bold py-2" 
          style={{ backgroundColor: btnColor, border: 'none' }}>
          Select Service
        </button>
      </div>
    </div>
  );

  return (
    <div className="container py-5 mt-4">
      <div className="text-center mb-5">
        <h1 className="fw-bold text-dark display-4 mb-2">Logistics Aggregator Platform</h1>
        <h5 className="text-primary fw-bold text-uppercase">One Solution for All Deliveries</h5>
      </div>

      <div className="row row-cols-1 row-cols-md-2 row-cols-lg-4 row-cols-xl-7 g-4 justify-content-center">
        <ServiceCard icon={<FiPackage />} title="Courier" desc="Express Delivery" btnColor="#27ae60" />
        <ServiceCard icon={<FiTruck />} title="Transport" desc="Heavy Haulage" btnColor="#d35400" />
        <ServiceCard icon={<FiBox />} title="Packers" desc="Home Shifting" btnColor="#f39c12" />
        <ServiceCard icon={<FiGlobe />} title="Global" desc="Sea Freight" btnColor="#8e44ad" />
        <ServiceCard icon={<FiBriefcase />} title="MSME" desc="Bulk Business" btnColor="#2980b9" />
        <ServiceCard icon={<FiSearch />} title="Tracking" desc="Real-time Tracking" btnColor="#7f8c8d" />
        <ServiceCard icon={<FiCpu />} title="AI Assist" desc="Smart Logistics" btnColor="#2c3e50" />
      </div>

      {/* --- POPUP BOOKING FORM (Modal) --- */}
      {showForm && (
        <div className="position-fixed top-0 start-0 w-100 h-100 d-flex align-items-center justify-content-center" 
             style={{ background: 'rgba(0,0,0,0.6)', zIndex: 1050 }}>
          <div className="bg-white p-4 rounded-4 shadow-lg position-relative" style={{ width: '100%', maxWidth: '450px' }}>
            <button className="position-absolute top-0 end-0 m-3 btn border-0" onClick={() => setShowForm(false)}><FiX size={24} /></button>
            <h4 className="fw-bold text-primary mb-3">Book {selectedService}</h4>
            <form onSubmit={handleWhatsApp}>
              <div className="mb-2"><input type="text" placeholder="Tumche Naav" className="form-control" required onChange={(e)=>setFormData({...formData, name: e.target.value})} /></div>
              <div className="mb-2"><input type="number" placeholder="WhatsApp Number" className="form-control" required onChange={(e)=>setFormData({...formData, phone: e.target.value})} /></div>
              <div className="row g-2 mb-2">
                <div className="col"><input type="text" placeholder="Kuthun (From)" className="form-control" required onChange={(e)=>setFormData({...formData, from: e.target.value})} /></div>
                <div className="col"><input type="text" placeholder="Kuthe (To)" className="form-control" required onChange={(e)=>setFormData({...formData, to: e.target.value})} /></div>
              </div>
              <div className="mb-3"><input type="text" placeholder="Weight (e.g. 5kg kiva 2 Ton)" className="form-control" required onChange={(e)=>setFormData({...formData, weight: e.target.value})} /></div>
              <button type="submit" className="btn btn-success w-100 fw-bold rounded-pill">Book via WhatsApp</button>
            </form>
          </div>
        </div>
      )}

      <style>{`.premium-card:hover { transform: translateY(-10px); }`}</style>
    </div>
  );
};

export default Home;
